import { useState } from 'react';
import { CircularProgress, TextField, Button } from '@mui/material';
import LockOpenIcon from '@mui/icons-material/LockOpen';
import { AuthServices, AuthServicesError } from '@/api/auth.api';
import { CallStatus } from '@/types/api.types';
import { PageCard } from '@/components/PageCard';
import { PageContainer } from '@/components/PageContainer';
import { StatusMessage } from '@/components/StatusMessage';
import { FormContainer } from '@/components/ui/FormContainer';
import { submitButtonStyle } from '@/constants/ThemeConstants';
import { getApiError } from '@/utils/apiError';

/**
 * Admin: clears any active OTP lockout for a user identified by email or phone.
 * The API returns 200 even when the identifier was never locked, so a successful
 * response simply means "the user can attempt OTP login again".
 */
export function AdminUnlockOtp() {
    const [identifier, setIdentifier] = useState('');
    const [status, setStatus] = useState<CallStatus>(CallStatus.NotStarted);
    const [errorMsg, setErrorMsg] = useState('');
    const [unlockedFor, setUnlockedFor] = useState('');

    const submit = async () => {
        const trimmed = identifier.trim();
        if (!trimmed) return;

        setStatus(CallStatus.InProgress);
        setErrorMsg('');
        setUnlockedFor('');
        try {
            const res = await AuthServices.AdminUnlockOtp(trimmed);
            const httpStatus = res?.data?.status ?? 0;
            if (httpStatus >= 200 && httpStatus < 300) {
                setUnlockedFor(trimmed);
                setStatus(CallStatus.Success);
            } else {
                setErrorMsg(AuthServicesError.AdminUnlockOtpError(httpStatus));
                setStatus(CallStatus.Failure);
            }
        } catch (err) {
            setErrorMsg(AuthServicesError.AdminUnlockOtpError(getApiError(err).httpStatus));
            setStatus(CallStatus.Failure);
        }
    };

    const inProgress = status === CallStatus.InProgress;
    const canSubmit = identifier.trim().length > 0 && !inProgress;

    return (
        <PageContainer
            icon={<LockOpenIcon color="primary" />}
            title="Unlock OTP"
            subtitle="Admin: clear an active OTP lockout for a user (email or phone)."
        >
            <PageCard>
                <FormContainer>
                    <TextField
                        label="User Email or Phone"
                        value={identifier}
                        onChange={e => setIdentifier(e.target.value)}
                        disabled={inProgress}
                        autoComplete="off"
                        autoFocus
                    />
                    <Button
                        variant="contained"
                        style={submitButtonStyle}
                        onClick={submit}
                        disabled={!canSubmit}
                    >
                        {inProgress ? <CircularProgress size={20} /> : 'Unlock'}
                    </Button>
                </FormContainer>
            </PageCard>

            <StatusMessage
                currentStatus={status}
                successMessage={unlockedFor ? `OTP lockout cleared for "${unlockedFor}". The user can attempt to log in again.` : undefined}
                failureMessage={errorMsg}
            />
        </PageContainer>
    );
}
